PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE incidents (
	id INTEGER NOT NULL, 
	trace_id VARCHAR(36) NOT NULL, 
	title VARCHAR(200) NOT NULL, 
	description TEXT NOT NULL, 
	reporter_email VARCHAR(254) NOT NULL, 
	attachment_type VARCHAR(10), 
	attachment_path VARCHAR(500), 
	status VARCHAR(20) NOT NULL, 
	created_at DATETIME NOT NULL, 
	updated_at DATETIME NOT NULL, linked_ticket_id INTEGER REFERENCES tickets(id), 
	PRIMARY KEY (id)
);
CREATE TABLE observability_events (
	id INTEGER NOT NULL, 
	trace_id VARCHAR(36) NOT NULL, 
	stage VARCHAR(20) NOT NULL, 
	incident_id INTEGER, 
	status VARCHAR(10) NOT NULL, 
	duration_ms INTEGER NOT NULL, 
	metadata TEXT NOT NULL, 
	created_at DATETIME NOT NULL, 
	PRIMARY KEY (id)
);
CREATE TABLE triage_results (
	id INTEGER NOT NULL, 
	incident_id INTEGER NOT NULL, 
	severity VARCHAR(4) NOT NULL, 
	affected_module VARCHAR(50) NOT NULL, 
	technical_summary TEXT NOT NULL, 
	suggested_files TEXT NOT NULL, 
	confidence_score FLOAT NOT NULL, 
	raw_llm_response TEXT, 
	created_at DATETIME NOT NULL, reasoning_chain TEXT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(incident_id) REFERENCES incidents (id)
);
CREATE TABLE tickets (
	id INTEGER NOT NULL, 
	incident_id INTEGER NOT NULL, 
	trello_card_id VARCHAR(100), 
	trello_card_url VARCHAR(500), 
	trello_list_id VARCHAR(100) NOT NULL, 
	status VARCHAR(20) NOT NULL, 
	created_at DATETIME NOT NULL, 
	resolved_at DATETIME, 
	PRIMARY KEY (id), 
	FOREIGN KEY(incident_id) REFERENCES incidents (id)
);
CREATE TABLE notification_logs (
	id INTEGER NOT NULL, 
	incident_id INTEGER NOT NULL, 
	channel VARCHAR(10) NOT NULL, 
	recipient VARCHAR(254) NOT NULL, 
	notification_type VARCHAR(30) NOT NULL, 
	content_summary TEXT NOT NULL, 
	status VARCHAR(10) NOT NULL, 
	sent_at DATETIME NOT NULL, 
	error_message TEXT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(incident_id) REFERENCES incidents (id)
);
CREATE UNIQUE INDEX ix_incidents_trace_id ON incidents (trace_id);
CREATE INDEX ix_observability_events_trace_id ON observability_events (trace_id);
CREATE INDEX ix_triage_results_incident_id ON triage_results (incident_id);
CREATE INDEX ix_tickets_incident_id ON tickets (incident_id);
CREATE INDEX ix_notification_logs_incident_id ON notification_logs (incident_id);
COMMIT;
